#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix-cycling-v2-lite-v2.py - Upgrade onglet CYCLISME v2 (avec fix CRLF).

Version corrigee : normalise les line endings (CRLF -> LF) avant de chercher
les anchors, pour fonctionner sur Windows.

Usage:
    cd <repo-pariscore>
    python fix-cycling-v2-lite-v2.py
"""
import base64
import json
import os
import sys

_DATA_B64 = ""
DATA = json.loads(base64.b64decode(_DATA_B64).decode("utf-8"))
FILES_BASE64 = DATA["files"]
PATCHES = DATA["patches"]


def normalize_lf(text):
    """Convertit les CRLF en LF pour que les anchors matchent."""
    return text.replace("\r\n", "\n").replace("\r", "\n")


def main():
    if not os.path.exists("pariscore.html"):
        print("ERREUR: pariscore.html non trouve.")
        sys.exit(1)

    print("=== Creation des fichiers ===")
    for path, b64 in FILES_BASE64.items():
        dirpath = os.path.dirname(path)
        if dirpath:
            os.makedirs(dirpath, exist_ok=True)
        content = base64.b64decode(b64)
        with open(path, "wb") as f:
            f.write(content)
        print("  OK " + path + " (" + str(len(content)) + " bytes)")

    for fname, patches_key in [("pariscore.js", "pariscore_js"), ("pariscore.html", "pariscore_html"), ("server.js", "server_js")]:
        if patches_key not in PATCHES or not PATCHES[patches_key]:
            continue
        print()
        print("=== Patch " + fname + " ===")
        with open(fname, "r", encoding="utf-8") as f:
            content = f.read()
        # NORMALISE CRLF -> LF pour que les anchors matchent
        content = normalize_lf(content)
        for i, patch in enumerate(PATCHES[patches_key]):
            old, new = patch["old"], patch["new"]
            # Normalise aussi les anchors (au cas ou)
            old_norm = normalize_lf(old)
            if old_norm in content:
                content = content.replace(old_norm, new, 1)
                print("  OK Patch " + str(i+1) + " applique")
            elif new in content:
                print("  WARN Patch " + str(i+1) + " deja applique")
            else:
                print("  FAIL Patch " + str(i+1) + " anchor non trouve!")
                # Affiche un extrait de l'anchor pour debug
                print("    Looking for (first 150 chars): " + old_norm[:150])
                sys.exit(1)
        with open(fname, "w", encoding="utf-8") as f:
            f.write(content)

    print()
    print("=== TERMINE ===")
    print()
    print("Prochaines etapes :")
    print('  1. git add -A')
    print('  2. git commit -m "feat(cycling): v2 hero + profile letour + classifications + leader"')
    print('  3. git push')
    print()
    print("Puis sur le VPS :")
    print("  bash deploy.sh")
    print("  pm2 restart pariscore")
    print()
    print("Puis regenerer les images sur le VPS :")
    print("  python3 scripts/scraper-letour-profiles.py")
    print("  python3 scripts/scraper-cycling-photos.py --from-favourites --force")
    print("  python3 scripts/scraper-cycling-translate.py --lang fr --force")
    print("  git add -A && git commit -m 'chore(cycling): regenerate images' && git push")


if __name__ == "__main__":
    main()
